<?php///   Naar database wegschrijven//@@@@include '../assets/dbconnect.php';include "../assets/formulas.php";	// producten laten zien$sql = "SELECT productnummer, productnaam, prijs, productpict1, productpict2, productpict3			 FROM alc_product			 ORDER BY productnaam";		// dit is dus de query om de producten op te halen$query = mysql_query($sql) or die (mysql_error()."<br>in file ".__FILE__." on line ".__LINE__); // als de query niet uitgevoerd wordt geeft die een foutmelding met bestandsnaam en regelnummer$num = mysql_num_rows($query); // Het aantal productenif(empty($num)) {	echo "<p>Er zijn geen producten gevonden.</p>\n";}else{	// Laat de producten zien	echo "<table width=\"100%\" border=\"0\" cellspacing=\"8\" cellpadding=\"8\" align=\"center\" cols=\"2\">";	$cnt=0;	while($product = mysql_fetch_object($query))	{		echo "<tr><td colspan=\"2\"><hr></td></tr>";		$cnt++;		if(is_even($cnt))		{			echo "<tr><form action=\"add.php\" method=\"post\">\n";			echo "<input type=\"hidden\" name=\"productnummer\" value=\"".$product->productnummer."\" />\n";			echo "<td><img src=\"productpicts/".$product->productpict1."\" border=\"0\" alt=\"".$product->productnaam."\"> </td>@@@xwidth=\"220\" xheight=\"220\"\n";			echo "<td><p><strong>".$product->productnummer."</strong> - ".$product->productnaam."<br />\n";			echo "Prijs per stuk: EUR ".$product->prijs."<br />\n";			echo "Aantal: <input type=\"text\" name=\"hoeveelheid\" size=\"2\" maxlength=\"2\" value=\"1\" />\n";			echo "<input type=\"submit\" value=\"Toevoegen\" /></p>\n";			echo "</td></form></tr>\n";		}else{			echo "<tr><form action=\"add.php\" method=\"post\">\n";			echo "<input type=\"hidden\" name=\"productnummer\" value=\"".$product->productnummer."\" />\n";			echo "<td><p><strong>".$product->productnummer."</strong> - ".$product->productnaam."<br />\n";			echo "Prijs per stuk: EUR ".$product->prijs."<br />\n";			echo "Aantal: <input type=\"text\" name=\"hoeveelheid\" size=\"2\" maxlength=\"2\" value=\"1\" />\n";			echo "<input type=\"submit\" value=\"Toevoegen\" /></p>\n";			echo "<td><img src=\"productpicts/".$product->productpict1."\"  border=\"0\" alt=\"".$product->productnaam."\"></td>@@@@xwidth=\"220\" xheight=\"220\"\n";			echo "</td></form></tr>\n";		}	}	echo "</table>";}?>